const runId = $input.first().json.runId;
const source = $input.first().json.source || {};
const blueprint = $input.first().json.blueprint || {};

// Truncate source text to ~6000 chars for extraction (use first + last portions)
const fullText = source.plainText || '';
const maxChars = 6000;
let sourceExcerpt;
if (fullText.length <= maxChars) {
  sourceExcerpt = fullText;
} else {
  sourceExcerpt = fullText.substring(0, 4000) + '\n\n[...middle truncated...]\n\n' + fullText.substring(fullText.length - 2000);
}

console.log(`[WF05][${runId}] Preparing extraction prompt. Source length: ${fullText.length} chars, excerpt: ${sourceExcerpt.length} chars`);

const sectionListFromBlueprint = (blueprint.canonicalSections || []).join(', ');

return [{
  json: {
    runId,
    source: $input.first().json.source,
    samples: $input.first().json.samples,
    options: $input.first().json.options,
    quality: $input.first().json.quality,
    blueprint,
    extractionPrompt: `You are a senior consulting business analyst and enterprise documentation specialist.

Your task is to extract a structured semantic model from the provided source BRD document.
Return ONLY valid JSON. No prose, no markdown fences.

Extract ALL of the following in structured JSON:
1. projectName — string
2. businessContext — string (2-3 sentences)
3. businessProblem — string (clear problem statement)
4. objectives — array of strings
5. stakeholders — array of { name, role, interest }
6. scopeIn — array of strings (what is included)
7. scopeOut — array of strings (what is excluded)
8. functionalRequirements — array of { id, title, description, priority (Must/Should/Nice) }
9. nonFunctionalRequirements — array of { id, category, description, priority }
10. reportingRequirements — array of strings
11. integrationRequirements — array of { system, type, description }
12. dataRequirements — array of strings
13. constraints — array of strings
14. assumptions — array of strings
15. dependencies — array of strings
16. risks — array of { title, probability (H/M/L), impact (H/M/L), mitigation }
17. approvals — array of { role, responsibility }
18. openQuestions — array of strings

Rules:
- Do NOT invent facts. If a field has no data, use an empty array or null.
- Preserve exact terminology from the source.
- Consolidate duplicates.
- If an item is implied but not explicit, include it and prefix with "[Assumed]"

SOURCE BRD DOCUMENT:
${sourceExcerpt}

Expected section structure from sample blueprint:
${sectionListFromBlueprint || 'Standard BRD sections'}

Return valid JSON only:`
  }
}];

const runId = $('Prepare Extraction Prompt').first().json.runId;
const rawResponse = $input.first().json.text || $input.first().json.content || '';

console.log(`[WF05][${runId}] Parsing semantic model response (${rawResponse.length} chars)...`);

let brdModel;
try {
  const clean = rawResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  brdModel = JSON.parse(clean);
} catch (e) {
  console.error(`[WF05][${runId}] JSON parse failed: ${e.message}`);
  // Return partial model with error flag
  brdModel = {
    _parseError: true,
    _rawResponse: rawResponse.substring(0, 500),
    projectName: 'Unknown',
    businessContext: '',
    businessProblem: '',
    objectives: [],
    stakeholders: [],
    scopeIn: [],
    scopeOut: [],
    functionalRequirements: [],
    nonFunctionalRequirements: [],
    reportingRequirements: [],
    integrationRequirements: [],
    dataRequirements: [],
    constraints: [],
    assumptions: [],
    dependencies: [],
    risks: [],
    approvals: [],
    openQuestions: [`[AUTO] Extraction failed: ${e.message} - Manual review required`]
  };
}

console.log(`[WF05][${runId}] Model extracted. FRs: ${(brdModel.functionalRequirements||[]).length}, NFRs: ${(brdModel.nonFunctionalRequirements||[]).length}, Risks: ${(brdModel.risks||[]).length}`);

return [{
  json: {
    runId,
    source: $('Prepare Extraction Prompt').first().json.source,
    samples: $('Prepare Extraction Prompt').first().json.samples,
    options: $('Prepare Extraction Prompt').first().json.options,
    quality: $('Prepare Extraction Prompt').first().json.quality,
    blueprint: $('Prepare Extraction Prompt').first().json.blueprint,
    brdModel
  }
}];
